"use client";

import { useEffect, useMemo, useState } from "react";
import { Button, Card, CardContent, Chip, Input, Spinner, TextArea, TextField, Label } from "@heroui/react";
import { getApiBaseUrl, getToken } from "@/lib/api-panel";
import { getErrorMessage } from "@/lib/error-message";
import { Code2, Play, Search, Terminal } from "lucide-react";
import { toast } from "sonner";

type ExplorerOperation = {
  operationId: string;
  method: string;
  path: string;
  summary: string;
  requiresAuth: boolean;
  queryParams: string[];
  pathParams: string[];
  tag?: string;
  hasRequestBody: boolean;
};

type ExplorerResponse = {
  status: number;
  ok: boolean;
  url: string;
  durationMs: number;
  headers: Record<string, string>;
  body: string;
};

function prettyJson(value: unknown): string {
  try {
    return JSON.stringify(value, null, 2);
  } catch {
    return String(value);
  }
}

export default function PanelApiExplorerPage() {
  const [operations, setOperations] = useState<ExplorerOperation[]>([]);
  const [loadingOperations, setLoadingOperations] = useState(true);

  const [search, setSearch] = useState("");
  const [selectedOperationId, setSelectedOperationId] = useState("");

  const [pathParams, setPathParams] = useState<Record<string, string>>({});
  const [queryParams, setQueryParams] = useState<Record<string, string>>({});

  const [sendAuth, setSendAuth] = useState(true);
  const [bodyText, setBodyText] = useState("{}");

  const [running, setRunning] = useState(false);
  const [response, setResponse] = useState<ExplorerResponse | null>(null);

  useEffect(() => {
    const load = async () => {
      setLoadingOperations(true);
      try {
        const res = await fetch("/api/panel/openapi", { cache: "no-store" });
        const payload = (await res.json()) as {
          operations?: ExplorerOperation[];
          error?: string;
        };

        if (!res.ok || !payload.operations) {
          throw new Error(payload.error || `Error ${res.status}`);
        }

        setOperations(payload.operations);
        if (payload.operations.length > 0) {
          setSelectedOperationId(payload.operations[0].operationId);
        }
      } catch (error: unknown) {
        toast.error(getErrorMessage(error, "No se pudo cargar panel-api.yaml"));
      } finally {
        setLoadingOperations(false);
      }
    };

    void load();
  }, []);

  const filteredOperations = useMemo(() => {
    const q = search.toLowerCase();

    return operations.filter((operation) => {
      return (
        operation.operationId.toLowerCase().includes(q) ||
        operation.path.toLowerCase().includes(q) ||
        operation.method.toLowerCase().includes(q) ||
        String(operation.tag || "").toLowerCase().includes(q)
      );
    });
  }, [operations, search]);

  const selectedOperation = useMemo(() => {
    return operations.find((operation) => operation.operationId === selectedOperationId) || null;
  }, [operations, selectedOperationId]);

  useEffect(() => {
    if (!selectedOperation) {
      return;
    }

    const nextPathParams: Record<string, string> = {};
    const nextQueryParams: Record<string, string> = {};

    selectedOperation.pathParams.forEach((param) => {
      nextPathParams[param] = "";
    });

    selectedOperation.queryParams.forEach((param) => {
      nextQueryParams[param] = "";
    });

    setPathParams(nextPathParams);
    setQueryParams(nextQueryParams);
    setSendAuth(selectedOperation.requiresAuth);
    setBodyText(selectedOperation.hasRequestBody ? "{}" : "");
    setResponse(null);
  }, [selectedOperationId, selectedOperation]);

  const executeOperation = async () => {
    if (!selectedOperation) {
      return;
    }

    let endpointPath = selectedOperation.path;

    for (const param of selectedOperation.pathParams) {
      const value = pathParams[param]?.trim();
      if (!value) {
        toast.error(`Falta path param: ${param}`);
        return;
      }

      endpointPath = endpointPath.replace(`{${param}}`, encodeURIComponent(value));
    }

    const baseUrl = getApiBaseUrl();
    const query = new URLSearchParams();

    Object.entries(queryParams).forEach(([key, value]) => {
      const trimmed = value.trim();
      if (trimmed) {
        query.set(key, trimmed);
      }
    });

    const queryString = query.toString();
    const requestUrl = `${baseUrl}${endpointPath}${queryString ? `?${queryString}` : ""}`;

    const headers: Record<string, string> = {};
    const upperMethod = selectedOperation.method.toUpperCase();

    if (sendAuth) {
      const token = getToken();
      if (!token) {
        toast.error("No hay token panel para enviar Authorization");
        return;
      }
      headers.Authorization = `Bearer ${token}`;
    }

    let body: string | undefined;
    const canSendBody = !["GET", "HEAD"].includes(upperMethod);

    if (canSendBody && bodyText.trim()) {
      try {
        const parsed = JSON.parse(bodyText);
        body = JSON.stringify(parsed);
        headers["Content-Type"] = "application/json";
      } catch {
        toast.error("Body JSON invalido");
        return;
      }
    }

    setRunning(true);
    const startedAt = performance.now();

    try {
      const res = await fetch(requestUrl, {
        method: upperMethod,
        headers,
        body,
      });

      const rawText = await res.text();
      let outputBody = rawText;

      if (rawText.trim()) {
        try {
          const parsed = JSON.parse(rawText) as unknown;
          outputBody = prettyJson(parsed);
        } catch {
          outputBody = rawText;
        }
      }

      const responseHeaders: Record<string, string> = {};
      res.headers.forEach((value, key) => {
        responseHeaders[key] = value;
      });

      setResponse({
        status: res.status,
        ok: res.ok,
        url: requestUrl,
        durationMs: Number((performance.now() - startedAt).toFixed(1)),
        headers: responseHeaders,
        body: outputBody || "(sin contenido)",
      });
    } catch (error: unknown) {
      toast.error(getErrorMessage(error, "Error de red al ejecutar la operacion"));
      setResponse({
        status: 0,
        ok: false,
        url: requestUrl,
        durationMs: Number((performance.now() - startedAt).toFixed(1)),
        headers: {},
        body: getErrorMessage(error),
      });
    } finally {
      setRunning(false);
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold font-[var(--font-heading)] text-gradient-purple-cyan">
          Panel API Explorer
        </h1>
        <p className="text-sm text-[var(--muted)] mt-1">
          Lee `panel-api.yaml` y ejecuta operaciones por `operationId`.
        </p>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-4">
        <Card className="bg-[var(--surface)] border border-[var(--border)]/40 xl:col-span-1">
          <Card.Content className="p-4 space-y-3">
            <TextField className="space-y-3 flex flex-col">
              <Label className="flex items-center gap-2">
                <Search className="h-4 w-4 text-[var(--foreground)]" />
                <span className="text-sm text-[var(--foreground)] font-medium">Operaciones</span>
              </Label>
              <Input
                placeholder="Buscar operationId, path, method..."
                value={search}
                onChange={(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => setSearch(e.target.value)}
              />
            </TextField>

            {loadingOperations ? (
              <div className="flex justify-center py-10">
                <Spinner size="lg" color="current" />
              </div>
            ) : (
              <div className="max-h-[34rem] overflow-auto space-y-2 pr-1">
                {filteredOperations.map((operation) => (
                  <Button
                    key={operation.operationId}
                    type="button"
                    variant="ghost"
                    onPress={() => setSelectedOperationId(operation.operationId)}
                    className={`h-auto w-full justify-start rounded-lg border p-3 text-left transition-colors ${selectedOperationId === operation.operationId
                      ? "border-white/30 bg-white/10"
                      : "border-white/10 bg-[var(--surface)] hover:border-white/25"
                      }`}
                  >
                    <div className="flex items-center justify-between gap-2">
                      <p className="text-xs font-semibold text-[var(--foreground)]">{operation.operationId}</p>
                      <Chip size="sm" variant="soft" color="default">
                        {operation.method}
                      </Chip>
                    </div>
                    <p className="text-[11px] text-[var(--muted)] mt-1 break-all">{operation.path}</p>
                    {operation.tag ? <p className="text-[11px] text-[var(--field-placeholder)] mt-1">{operation.tag}</p> : null}
                  </Button>
                ))}
              </div>
            )}
          </Card.Content>
        </Card>

        <Card className="bg-[var(--surface)] border border-[var(--border)]/40 xl:col-span-2">
          <Card.Content className="p-4 space-y-4">
            {!selectedOperation ? (
              <p className="text-sm text-[var(--muted)]">Selecciona una operaci├│n.</p>
            ) : (
              <>
                <div className="space-y-1">
                  <div className="flex items-center gap-2">
                    <Code2 className="h-4 w-4 text-[var(--foreground)]" />
                    <p className="text-sm font-medium text-zinc-100">{selectedOperation.operationId}</p>
                    <Chip size="sm" variant="soft" color="default">
                      {selectedOperation.method}
                    </Chip>
                    {selectedOperation.requiresAuth ? (
                      <Chip size="sm" variant="soft" color="default">
                        BearerAuth
                      </Chip>
                    ) : null}
                  </div>
                  <p className="text-xs text-[var(--muted)] break-all">{selectedOperation.path}</p>
                  <p className="text-xs text-[var(--muted)]">{selectedOperation.summary}</p>
                </div>

                {selectedOperation.pathParams.length > 0 ? (
                  <div className="space-y-2">
                    <p className="text-xs text-[var(--muted)] uppercase tracking-wide">Path params</p>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                      {selectedOperation.pathParams.map((param) => (
                        <TextField key={param} className="flex flex-col gap-1">
                          <Label className="text-xs text-[var(--muted)]">{param}</Label>
                          <Input
                            placeholder={param}
                            value={pathParams[param] || ""}
                            onChange={(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => setPathParams((prev) => ({ ...prev, [param]: e.target.value }))}
                          />
                        </TextField>
                      ))}
                    </div>
                  </div>
                ) : null}

                {selectedOperation.queryParams.length > 0 ? (
                  <div className="space-y-2">
                    <p className="text-xs text-[var(--muted)] uppercase tracking-wide">Query params</p>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                      {selectedOperation.queryParams.map((param) => (
                        <TextField key={param} className="flex flex-col gap-1">
                          <Label className="text-xs text-[var(--muted)]">{param}</Label>
                          <Input
                            placeholder={param}
                            value={queryParams[param] || ""}
                            onChange={(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => setQueryParams((prev) => ({ ...prev, [param]: e.target.value }))}
                          />
                        </TextField>
                      ))}
                    </div>
                  </div>
                ) : null}

                {selectedOperation.hasRequestBody ? (
                  <TextField className="space-y-2 flex flex-col">
                    <Label className="text-xs text-[var(--muted)] uppercase tracking-wide">Body JSON</Label>
                    <TextArea
                      value={bodyText}
                      onChange={(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => setBodyText(e.target.value)}
                      rows={8}
                      className="font-mono text-xs"
                    />
                  </TextField>
                ) : null}

                <div className="flex flex-wrap items-center gap-2">
                  <Button
                    size="sm"
                    variant={sendAuth ? "primary" : "ghost"}
                    onPress={() => setSendAuth((prev) => !prev)}
                  >
                    Authorization: {sendAuth ? "ON" : "OFF"}
                  </Button>
                  <Button
                    size="sm"
                    onPress={executeOperation}
                    isPending={running}
                    className="bg-gradient-to-r from-zinc-700 to-black"
                  >
                    <Play className="h-3.5 w-3.5" /> Ejecutar
                  </Button>
                </div>
              </>
            )}
          </Card.Content>
        </Card>
      </div>

      <Card className="bg-[var(--surface)] border border-[var(--border)]/40">
        <Card.Content className="p-4 space-y-3">
          <div className="flex items-center gap-2">
            <Terminal className="h-4 w-4 text-[var(--foreground)]" />
            <p className="text-sm font-medium text-[var(--foreground)]">Respuesta</p>
          </div>

          {response ? (
            <>
              <div className="flex flex-wrap gap-2 text-xs">
                <Chip size="sm" variant="soft" color="default">
                  status {response.status}
                </Chip>
                <Chip size="sm" variant="soft" color="default">
                  {response.ok ? "ok" : "error"}
                </Chip>
                <Chip size="sm" variant="soft" color="default">
                  {response.durationMs} ms
                </Chip>
              </div>
              <p className="text-[11px] text-[var(--muted)] break-all">{response.url}</p>
              <details className="rounded-lg border border-white/10 bg-[var(--surface)] p-2">
                <summary className="cursor-pointer text-xs text-[var(--muted)]">Headers</summary>
                <pre className="mt-2 text-xs text-[var(--muted)] overflow-auto">{prettyJson(response.headers)}</pre>
              </details>
              <pre className="rounded-lg border border-white/10 bg-[var(--surface)] p-3 text-xs text-[var(--foreground)] overflow-auto max-h-[28rem] whitespace-pre-wrap">
                {response.body}
              </pre>
            </>
          ) : (
            <p className="text-sm text-[var(--muted)]">Aun no se ha ejecutado ninguna operaci├│n.</p>
          )}
        </Card.Content>
      </Card>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import {
    Card,
    CardContent,
    Table,
    Button,
    Input,
    TextField,
    Form,
    Fieldset,
    Label,
    Spinner,
} from "@heroui/react";
import { toast } from "sonner";
import { listPanelCoupons } from "@/lib/api-panel";

export default function CouponsPage() {
    const [loading, setLoading] = useState(true);
    const [coupons, setCoupons] = useState<any[]>([]);
    const [page, setPage] = useState(1);
    const [query, setQuery] = useState("");

    const fetchCoupons = async () => {
        try {
            setLoading(true);
            const res = await listPanelCoupons({ page, query });
            setCoupons(res.coupons as any[] || []);
        } catch (error: any) {
            toast.error(error.message || "Error al cargar cupones");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchCoupons();
    }, [page, query]);

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold font-[var(--font-heading)] text-gradient-purple-cyan">
                        Cupones
                    </h1>
                    <p className="text-sm text-[var(--muted)] mt-1">Gestiona los descuentos de tu tienda</p>
                </div>
                <Button
                    type="button"

                    onPress={() => toast.info("Crear cupon proximamente")}
                >
                    Nuevo Cupon
                </Button>
            </div>

            <div className="flex flex-col lg:flex-row gap-6 items-start">
                <div className="w-full lg:w-1/3 shrink-0">
                    <Card className="bg-[var(--surface)] border border-[var(--border)]/40">
                        <Card.Content className="p-5">
                            <Form>
                                <Fieldset className="space-y-4">
                                    <Fieldset.Legend className="text-[var(--foreground)] font-semibold">Filtros</Fieldset.Legend>
                                    <p className="text-xs text-[var(--muted)] mb-2">Busca cupones por codigo.</p>

                                    <div className="grid grid-cols-1 gap-3">
                                        <TextField className="space-y-1 flex flex-col">
                                            <Label className="text-xs text-[var(--muted)]">Buscar</Label>
                                            <Input
                                                placeholder="ej. VERANO2026"
                                                value={query}
                                                onChange={(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => setQuery(e.target.value)}
                                            />
                                        </TextField>
                                    </div>
                                </Fieldset>
                            </Form>
                        </Card.Content>
                    </Card>
                </div>

                <div className="w-full lg:w-2/3">
                    <Card className="bg-[var(--surface)] border border-[var(--border)]/40">
                        <Card.Content className="p-5">
                            {loading ? (
                                <div className="flex justify-center py-20">
                                    <Spinner size="lg" color="current" />
                                </div>
                            ) : coupons.length === 0 ? (
                                <div className="text-center py-10 text-[var(--muted)]">
                                    No se encontraron cupones.
                                </div>
                            ) : (
                                <Table>
                                    <Table.Header>
                                        <Table.Column>Codigo</Table.Column>
                                        <Table.Column>Descuento</Table.Column>
                                        <Table.Column>Min. Compra</Table.Column>
                                        <Table.Column>Estado</Table.Column>
                                    </Table.Header>
                                    <Table.Body>
                                        {coupons.map((coupon) => (
                                            <Table.Row key={coupon.id}>
                                                <Table.Cell className="font-mono text-emerald-400">{coupon.code}</Table.Cell>
                                                <Table.Cell>
                                                    {coupon.discount_type === "PERCENTAGE"
                                                        ? `${coupon.discount_value}%`
                                                        : `$${coupon.discount_value}`}
                                                </Table.Cell>
                                                <Table.Cell>{coupon.min_purchase ? `$${coupon.min_purchase}` : "-"}</Table.Cell>
                                                <Table.Cell>{coupon.status}</Table.Cell>
                                            </Table.Row>
                                        ))}
                                    </Table.Body>
                                </Table>
                            )}
                        </Card.Content>
                    </Card>
                </div>
            </div>
        </div>
    );
}

"use client";

import { Card, CardContent } from "@heroui/react";
import { PackageSearch, ShoppingCart, Users, AlertTriangle } from "lucide-react";
import { useEffect, useState } from "react";
import { getPanelInventoryValuation } from "@/lib/api-panel";

export default function DashboardPage() {
    const [stats, setStats] = useState<any>(null);

    useEffect(() => {
        getPanelInventoryValuation()
            .then(setStats)
            .catch((err) => console.error("Could not load stats:", err));
    }, []);

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-2xl font-bold font-[var(--font-heading)] text-gradient-purple-cyan">
                    Panel de Tienda
                </h1>
                <p className="text-[var(--muted)] mt-1">Resumen general de tu negocio</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <Card className="bg-[var(--surface)] border border-[var(--border)]">
                    <Card.Content className="p-6">
                        <div className="flex items-center gap-4">
                            <div className="p-3 rounded-xl bg-[var(--accent)]/10 text-[var(--accent)]">
                                <PackageSearch className="w-6 h-6" />
                            </div>
                            <div>
                                <p className="text-sm text-[var(--muted)]">Total Inventario (Retail)</p>
                                <p className="text-2xl font-bold text-[var(--foreground)]">
                                    ${stats?.total_retail_value || 0}
                                </p>
                            </div>
                        </div>
                    </Card.Content>
                </Card>
            </div>
            {/* The rest of the dashboard layout left blank for future widgets */}
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import {
    Card,
    CardContent,
    Table,
    Button,
    Input,
    TextField,
    Form,
    Fieldset,
    Label,
    Spinner,
} from "@heroui/react";
import { toast } from "sonner";
import { listPanelInventoryMovements } from "@/lib/api-panel";

export default function InventoryPage() {
    const [loading, setLoading] = useState(true);
    const [movements, setMovements] = useState<any[]>([]);
    const [page, setPage] = useState(1);
    const [query, setQuery] = useState("");

    const fetchMovements = async () => {
        try {
            setLoading(true);
            const res = await listPanelInventoryMovements({ page, query });
            setMovements(res.movements as any[] || []);
        } catch (error: any) {
            toast.error(error.message || "Error al cargar movimientos de stock");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchMovements();
    }, [page, query]);

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold font-[var(--font-heading)] text-gradient-purple-cyan">
                        Inventario
                    </h1>
                    <p className="text-sm text-[var(--muted)] mt-1">Revisa el historial de movimientos de stock</p>
                </div>
                <Button
                    type="button"

                    onPress={() => toast.info("Ajuste manual de stock proximamente")}
                >
                    Ajustar Stock
                </Button>
            </div>

            <div className="flex flex-col lg:flex-row gap-6 items-start">
                <div className="w-full lg:w-1/3 shrink-0">
                    <Card className="bg-[var(--surface)] border border-[var(--border)]/40">
                        <Card.Content className="p-5">
                            <Form>
                                <Fieldset className="space-y-4">
                                    <Fieldset.Legend className="text-[var(--foreground)] font-semibold">Filtros</Fieldset.Legend>
                                    <p className="text-xs text-[var(--muted)] mb-2">Busca movimientos por ID de producto o motivo.</p>

                                    <div className="grid grid-cols-1 gap-3">
                                        <TextField className="space-y-1 flex flex-col">
                                            <Label className="text-xs text-[var(--muted)]">Buscar</Label>
                                            <Input
                                                placeholder="ej. TCG-123 o 'venta'"
                                                value={query}
                                                onChange={(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => setQuery(e.target.value)}
                                            />
                                        </TextField>
                                    </div>
                                </Fieldset>
                            </Form>
                        </Card.Content>
                    </Card>
                </div>

                <div className="w-full lg:w-2/3">
                    <Card className="bg-[var(--surface)] border border-[var(--border)]/40">
                        <Card.Content className="p-5">
                            {loading ? (
                                <div className="flex justify-center py-20">
                                    <Spinner size="lg" color="current" />
                                </div>
                            ) : movements.length === 0 ? (
                                <div className="text-center py-10 text-[var(--muted)]">
                                    No se encontraron movimientos.
                                </div>
                            ) : (
                                <Table>
                                    <Table.Header>
                                        <Table.Column>Fecha</Table.Column>
                                        <Table.Column>Producto ID</Table.Column>
                                        <Table.Column>Tipo</Table.Column>
                                        <Table.Column>Cantidad</Table.Column>
                                        <Table.Column>Motivo</Table.Column>
                                    </Table.Header>
                                    <Table.Body>
                                        {movements.map((mov) => (
                                            <Table.Row key={mov.id}>
                                                <Table.Cell>{new Date(mov.created_at).toLocaleDateString()}</Table.Cell>
                                                <Table.Cell>{mov.product_id}</Table.Cell>
                                                <Table.Cell>{mov.movement_type}</Table.Cell>
                                                <Table.Cell>{mov.quantity > 0 ? `+${mov.quantity}` : mov.quantity}</Table.Cell>
                                                <Table.Cell>{mov.reason || "-"}</Table.Cell>
                                            </Table.Row>
                                        ))}
                                    </Table.Body>
                                </Table>
                            )}
                        </Card.Content>
                    </Card>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Image from "next/image";
import {
    TextField, Label, InputGroup, InputGroupPrefix, InputGroupSuffix, Input,
    Button, Card, CardContent, Form
} from "@heroui/react";
import { loginPanel, setTokens, setTenantId } from "@/lib/api-panel";
import { Eye, EyeOff, Mail, Lock } from "lucide-react";
import { toast } from "sonner";

export default function LoginPage() {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [showPassword, setShowPassword] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const router = useRouter();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
